-- ─── H1 2026 Posts Seed ───────────────────────────────────────────────────────
-- Run this in the Supabase SQL editor AFTER running schema.sql
-- to seed X and LinkedIn data for the H1 Town Hall report.
--
-- Step 1: Create the posts table (if not done already)
-- Step 2: Paste and run this file
-- Step 3: Go to /posts in Audian and click "Sync from API" for Instagram
-- ─────────────────────────────────────────────────────────────────────────────
-- X / Twitter posts (Jan–Mar 2026)
ON CONFLICT (platform, post_id) DO UPDATE SET likes = EXCLUDED.likes, impressions = EXCLUDED.impressions, comments = EXCLUDED.comments;

-- LinkedIn daily aggregate data (Jan–Mar 2026)
ON CONFLICT (platform, post_id) DO UPDATE SET likes = EXCLUDED.likes, impressions = EXCLUDED.impressions;
